from typing import Iterable, Iterator
import json

def extract(filepath: str) -> Iterator[dict]:
    """Yield one record at a time — never loads full file"""
    with open(filepath) as f:
        for line in f:
            yield json.loads(line)  # JSONL format

def filter_adults(records: Iterable[dict]) -> Iterator[dict]:
    """Pass-through filter: only yield adults"""
    for record in records:
        if int(record.get("age", 0)) >= 18:
            yield record

def normalize(records: Iterable[dict]) -> Iterator[dict]:
    """Transform each record"""
    for record in records:
        yield {
            "id": record["user_id"],
            "name": record["name"].strip().title(),
            "age": int(record["age"]),
        }

def load(records: Iterable[dict], filepath: str) -> int:
    """Consume the pipeline and write output"""
    count = 0
    with open(filepath, "w") as f:
        for record in records:
            f.write(json.dumps(record) + "\n")
            count += 1
    return count

# Build the pipeline — nothing executes yet
raw        = extract("users.jsonl")
adults     = filter_adults(raw)
normalized = normalize(adults)

# Execution starts here when the consumer pulls data
processed = load(normalized, "output.jsonl")
print(f"Processed {processed} records")

from functools import reduce
from typing import Callable, TypeVar

T = TypeVar("T")

def pipe(*functions: Callable) -> Callable:
    """
    Compose functions left-to-right.
    pipe(f, g, h)(x) == h(g(f(x)))
    """
    return reduce(lambda f, g: lambda x: g(f(x)), functions)

# Define each stage as a pure function on iterables
def parse_ages(records):
    return (
        {**r, "age": int(r["age"])}
        for r in records
    )

def filter_adults(records):
    return (r for r in records if r["age"] >= 18)

def normalize_names(records):
    return (
        {**r, "name": r["name"].strip().title()}
        for r in records
    )

def add_tier(records):
    def tier(age):
        if age < 25: return "young"
        if age < 60: return "mid"
        return "senior"
    return ({**r, "tier": tier(r["age"])} for r in records)

# Compose into a single transformation function
transform_pipeline = pipe(
    parse_ages,
    filter_adults,
    normalize_names,
    add_tier,
)

# Apply to any iterable source
import json

with open("users.jsonl") as f:
    source = (json.loads(line) for line in f)
    results = list(transform_pipeline(source))

