from typing import Callable, Iterator
import json

@dataclass
class RoutedRecord:
    record: dict
    route: str  # Destination label

def router(records: Iterator[dict]) -> Iterator[RoutedRecord]:
    """
    Inspect each record and attach a route label.
    This stage makes no transformation — only routing decisions.
    """
    for r in records:
        age = int(r.get("age", 0))
        country = r.get("country", "")

        if age < 18:
            route = "minors"
        elif country == "US":
            route = "us_adults"
        elif country in ("UK", "CA", "AU"):
            route = "commonwealth_adults"
        else:
            route = "international"

        yield RoutedRecord(record=r, route=route)

def branch_dispatcher(
    routed_stream: Iterator[RoutedRecord],
    handlers: dict[str, Callable[[dict], None]],
    default_handler: Callable[[dict], None] | None = None,
) -> None:
    """
    Dispatch each record to the appropriate handler based on route.
    Handlers are callables that consume a single record (sinks).
    """
    for item in routed_stream:
        handler = handlers.get(item.route, default_handler)
        if handler:
            handler(item.record)
        else:
            print(f"No handler for route '{item.route}', dropping record")

# Define per-branch sinks
us_output = open("us_adults.jsonl", "w")
intl_output = open("international.jsonl", "w")

def handle_us(record: dict):
    us_output.write(json.dumps(record) + "\n")

def handle_intl(record: dict):
    intl_output.write(json.dumps(record) + "\n")

def handle_minors(record: dict):
    pass  # Drop silently

# Wire up
with open("users.jsonl") as f:
    source = (json.loads(line) for line in f)
    routed = router(source)
    branch_dispatcher(
        routed,
        handlers={
            "us_adults": handle_us,
            "commonwealth_adults": handle_us,  # Same handler
            "international": handle_intl,
            "minors": handle_minors,
        }
    )

us_output.close()
intl_output.close()

import json
import hashlib
from pathlib import Path
from dataclasses import dataclass

@dataclass
class Checkpoint:
    checkpoint_dir: Path
    pipeline_id: str

    def _path(self) -> Path:
        return self.checkpoint_dir / f"{self.pipeline_id}.json"

    def save(self, last_processed_id: str, records_done: int) -> None:
        self._path().parent.mkdir(parents=True, exist_ok=True)
        state = {
            "last_id": last_processed_id,
            "records_done": records_done,
        }
        self._path().write_text(json.dumps(state))

    def load(self) -> dict | None:
        p = self._path()
        if p.exists():
            return json.loads(p.read_text())
        return None

    def clear(self) -> None:
        p = self._path()
        if p.exists():
            p.unlink()

def resumable_pipeline(
    source_file: str,
    output_file: str,
    checkpoint: Checkpoint,
    transform_fn,
    checkpoint_every: int = 1000,
) -> int:
    # Recover state from checkpoint if available
    state = checkpoint.load()
    last_id = state["last_id"] if state else None
    records_done = state["records_done"] if state else 0
    skip_until_found = last_id is not None

    print(f"Resuming from: {last_id}, records already done: {records_done}")

    count = records_done
    mode = "a" if last_id else "w"  # Append if resuming

    with open(source_file) as src, open(output_file, mode) as dst:
        for line in src:
            record = json.loads(line)
            record_id = record.get("user_id")

            # Skip records already processed
            if skip_until_found:
                if record_id == last_id:
                    skip_until_found = False
                continue

            # Process record
            try:
                result = transform_fn(record)
                if result:
                    dst.write(json.dumps(result) + "\n")
                    count += 1
            except Exception as e:
                print(f"Error on record {record_id}: {e}")
                continue

            # Save checkpoint periodically
            if count % checkpoint_every == 0:
                dst.flush()  # Ensure output is on disk before checkpointing
                checkpoint.save(record_id, count)
                print(f"Checkpoint saved at record {count}")

    checkpoint.clear()  # Clean up on successful completion
    return count
